// Schema Validator: parse Gemini output and validate before any API call.
// Merge voice/text paths — either node could have fired.
const geminiRaw = items[0].json;
const ctx = $('Identity Router').first().json;

let parsed;
try {
  const rawText = geminiRaw.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  parsed = JSON.parse(rawText);
} catch(e) {
  return [{ json: { validationError: 'Gemini returned invalid JSON: ' + e.message, chatId: ctx.chatId } }];
}

const allowed = {
  admin: ['beds24.getOccupancy','beds24.listBookings','beds24.getRevenue','beds24.blockRoom','beds24.updatePrice','beds24.cancelBooking','tastyigniter.listReservations','tastyigniter.checkAvailability','tastyigniter.deleteReservation','hievents.getTicketCounts','hievents.listEvents','unknown'],
  collaborator: ['beds24.getOccupancy','tastyigniter.listReservations','tastyigniter.checkAvailability','hievents.getTicketCounts','unknown']
};

if (parsed.action === 'unknown') {
  return [{ json: { validationError: parsed.humanReadableSummary || 'Could not interpret command', chatId: ctx.chatId } }];
}

if (!allowed[ctx.tier]?.includes(parsed.action)) {
  return [{ json: { validationError: `Action '${parsed.action}' not allowed for tier '${ctx.tier}'`, chatId: ctx.chatId } }];
}

if (!parsed.endpoint || !parsed.method) {
  return [{ json: { validationError: 'Gemini missing endpoint or method', chatId: ctx.chatId } }];
}

// Validate payload numeric fields
if (parsed.payload?.price !== undefined && (isNaN(parsed.payload.price) || parsed.payload.price <= 0)) {
  return [{ json: { validationError: 'Invalid price value in payload', chatId: ctx.chatId } }];
}

return [{ json: { ...parsed, chatId: ctx.chatId, tier: ctx.tier, valid: true } }];

