// Store pending action and prepare confirmation message for Telegram
const action = items[0].json;
const actionKey = Date.now().toString(36);
const staticData = $getWorkflowStaticData('global');
if (!staticData.pendingActions) staticData.pendingActions = {};
staticData.pendingActions[actionKey] = {
  action: action.action,
  endpoint: action.endpoint,
  method: action.method,
  payload: action.payload,
  confirmationMessage: action.confirmationMessage,
  humanReadableSummary: action.humanReadableSummary,
  ts: Date.now()
};
return [{ json: { actionKey, chatId: action.chatId, confirmationMessage: action.confirmationMessage } }];

// Audit log: record every AI-triggered API mutation
const ctx = items[0].json;
const apiCtx = $('Schema Validator').first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.auditLog) staticData.auditLog = [];
staticData.auditLog.push({
  ts: new Date().toISOString(),
  user: apiCtx.tier,
  action: apiCtx.action,
  endpoint: apiCtx.endpoint,
  payload: apiCtx.payload,
  result: ctx.error ? 'error' : 'success',
  n8nExecutionId: $execution.id
});
// Keep last 500 entries
if (staticData.auditLog.length > 500) staticData.auditLog = staticData.auditLog.slice(-500);
return [{ json: { ...ctx, auditLogged: true, chatId: apiCtx.chatId, summary: apiCtx.humanReadableSummary } }];
